import React from 'react'
import { useState, useEffect } from "react";
import PropTypes from 'prop-types'
import {Nav, Navbar,Container, NavbarBrand} from 'react-bootstrap'
import navIcon1 from '../assets/img/nav-icon1.svg';
import navIcon2 from '../assets/img/nav-icon2.svg';
import navIcon3 from '../assets/img/nav-icon3.svg';
import{Browser as Router} from "react-router-dom";
// import { HashLink } from 'react-router-hash-link';







export default function NavBar(props) {

 const[activeLink, setActiveLink]= useState('home');

 const onUpdateActiveLink=(value)=>{
    setActiveLink(value);
}
  return (
    <>
      <Navbar className="navbar navbar-expand-lg">
        <Container>
          {/* <Navbar.Brand href="/">
            
          </Navbar.Brand> */}
          <Nav.Link className="navbar-brand mx-3 fw-bold text-white" href="/">{props.title}</Nav.Link>
          <Navbar.Toggle aria-controls="basic-navbar-nav" aria-expanded="false" aria-label="Toggle navigation">
            <span className="navbar-toggler-icon"></span>
          </Navbar.Toggle>

          <div className="collapse navbar-collapse custom-navbar" id="navbarSupportedContent">
            <ul className="navbar-nav ms-auto">
              <Nav className="nav-item">
                <Nav.Link   href="#home" className={`nav-link text-white ${activeLink === 'home' ? 'active nav-item' : 'nav-item'}`} onClick={()=> onUpdateActiveLink('home')}>Home</Nav.Link>
              </Nav>
              <li className="nav-item">
                <a  href="#getintouch" className={`nav-link text-white ${activeLink === 'getintouch' ? 'active nav-item' : 'nav-item'}`} onClick={()=> onUpdateActiveLink('getintouch')} >{props.getintouch}</a>
              </li>
              <li className="nav-item">
                <a  href="#about" className={`nav-link text-white ${activeLink === 'about' ? 'active nav-item' : 'nav-item'}`} onClick={()=> onUpdateActiveLink('about')}>{props.aboutText}</a>
              </li>        
            </ul>
            <span className="navbar-text">
                <div className="social-icon">
                  <a href="#"><img src={navIcon1} alt="" /></a>
                  <a href="#"><img src={navIcon2} alt="" /></a>
                  <a href="#"><img src={navIcon3} alt="" /></a>
                </div>
                  {/* <HashLink to='#connect'>
                    <button className="vvd"><span>Let's Connect</span></button>
                  </HashLink> */}
                </span>
            </div>
        </Container>
      </Navbar>
    </>

  )
}

NavBar.prototype={
  title:PropTypes.string.isRequired,
  videos:PropTypes.string.isRequired
}

NavBar.defaultProps={
  title:"Alan.is",
  getintouch:"Get in Touch",
  aboutText:"About me"
};
